// n8n Code node — "Run Once for All Items"
// Processa TODOS os itens de entrada, cada um pelo seu id/Reevaluation próprio.
const items = $input.all();

// valor de corte vindo do node anterior "parameters" (igual para todos os itens)
function paraNumero(v) {
  if (typeof v === 'number') return v;
  if (typeof v === 'string' && v.trim() !== '' && !isNaN(Number(v))) return Number(v);
  return v;
}
const corte = paraNumero($('parameters').first().json.corte);

const REMOVER = [
  'par1', 'just1', 'par2', 'just2', 'par3', 'just3',
  'par4', 'just4', 'par5', 'just5',
  'reason',
  'gallery', 'capa', 'acessibilidade', 'resumo',
  'média', 'aproved',  // saem da raiz (vão para dentro do Reevaluation)
];

function parseSeForString(v) {
  if (typeof v !== 'string') return v;
  const s = v.trim();
  if (!s) return v;
  try { return JSON.parse(s); } catch { return v; }
}

// timestamp atual no horário do Brasil (America/Sao_Paulo), ISO com offset
function tsBrasil() {
  return new Date()
    .toLocaleString('sv-SE', { timeZone: 'America/Sao_Paulo' })
    .replace(' ', 'T') + '-03:00';
}

// monta Reevaluation acumulando médias, sobrescrevendo aproved e updated_at
function montarReevaluation(o) {
  const mediaAtual = o['média'] ?? null;
  const aprovedAtual = o.aproved ?? null;
  let prev = o.Reevaluation;
  if (typeof prev === 'string') { try { prev = JSON.parse(prev); } catch { prev = null; } }
  let medias = [];
  if (prev && prev['média'] != null) {
    medias = Array.isArray(prev['média']) ? [...prev['média']] : [prev['média']];
  }
  if (mediaAtual != null) medias.push(mediaAtual);
  return {
    'média': medias,
    aproved: aprovedAtual,
    updated_at: tsBrasil(),
  };
}

function transformar(entrada) {
  const o = { ...entrada };

  if ('subtipos' in o) { o.subsegmento = o.subtipos; delete o.subtipos; }
  // crated_at mantido como veio (sem rename)

  if ('fotos' in o)              o.fotos = parseSeForString(o.fotos);
  if ('reviews' in o)            o.reviews = parseSeForString(o.reviews);
  if ('distribuicao_notas' in o) o.distribuicao_notas = parseSeForString(o.distribuicao_notas);
  if ('horarios' in o)           o.horarios = parseSeForString(o.horarios);

  if ('nota' in o)           o.nota = paraNumero(o.nota);
  if ('qtd_avaliacoes' in o) o.qtd_avaliacoes = paraNumero(o.qtd_avaliacoes);
  if ('qtd_fotos' in o)      o.qtd_fotos = paraNumero(o.qtd_fotos);

  // minimum_grade recebe o valor de corte do node "parameters"
  o.minimum_grade = corte;

  // monta o Reevaluation ANTES de remover média/aproved da raiz
  o.Reevaluation = montarReevaluation(o);

  for (const campo of REMOVER) delete o[campo];

  return o;
}

return items.map((item) => ({ json: transformar(item.json) }));

// === n8n Code Node (Run Once for All Items) ===

// 1. Normaliza a entrada: monta uma lista única de objetos,
//    venham eles como itens separados ou como um array dentro de um item.
let registros = [];

for (const item of items) {
  const j = item.json;
  if (Array.isArray(j)) {
    registros.push(...j);
  } else if (Array.isArray(j.data)) {   // caso venha embrulhado em .data
    registros.push(...j.data);
  } else {
    registros.push(j);
  }
}

// 2. Extrai o minimum_reviews (linha de config no fim do array, sem id)
let minimumReviews = null;
const cfg = registros.find(
  (r) => r && r.minimum_reviews !== undefined && r.id === undefined
);
if (cfg) minimumReviews = cfg.minimum_reviews;

// 3. Injeta o campo em cada estabelecimento (linhas que têm id)
return registros
  .filter((r) => r && r.id !== undefined)
  .map((r) => ({
    json: {
      ...r,
      minimum_reviews: minimumReviews,
    },
  }));

const campos = [
  "pais",
  "estado",
  "cidade",
  "bairro",
  "qtd_filtros_localizacao",
  "avaliar_todos",
  "corte",
  "minimum_reviews"
];

return $('parameters').all().map(item => {
  const out = {};
  for (const k of campos) {
    if (k in item.json) out[k] = item.json[k];
  }
  return { json: out };
});
